mapper.select:
select p.id, p.title, p.difficulty, p.status, p.created_at, p.updated_at, p.accepted_count from problems p join problem_tags pt on pt.problem_id = p.id where p.status = 1 and pt.tag_id in
#{tagId}
and not exists ( select 1 from submissions s where s.user_id = #{userId} and s.problem_id = p.id )
and p.id not in
#{pid}
group by p.id, p.title, p.difficulty, p.status, p.created_at, p.updated_at, p.accepted_count order by p.accepted_count asc, p.id desc limit #{limit}

select p.id, p.title, p.difficulty, p.status, p.created_at, p.updated_at
from problems p
where p.status = 1
  and p.difficulty = #{difficulty}
  and not exists (
    select 1 from submissions s where s.user_id = #{userId} and s.problem_id = p.id
  )

      and p.id not in

          #{pid}


order by p.accepted_count asc, p.id desc
limit #{limit}

mapper.insert:
insert into recommendation_records (
    user_id, trigger_source, trigger_ref_id, resource_type, resource_id, problem_id, reason_text, score, recommended_at
)
values (
    #{userId}, #{triggerSource}, #{triggerRefId}, #{resourceType}, #{resourceId}, #{problemId}, #{reasonText}, #{score}, now()
)
